import { Component, Input, OnChanges, OnInit, Optional, SimpleChanges } from '@angular/core';
import { Color } from 'ol/color';
import { Stroke } from 'ol/style';
import { StyleCircleComponent } from './circle.component';
import { StyleComponent } from './style.component';
import { StyleTextComponent } from './text.component';

@Component({
  selector: 'map-style-stroke',
  template: '<div class="map-style-stroke"></div>'
})
export class StyleStrokeComponent implements OnInit, OnChanges {
  instance: Stroke;
  /* the typings do not have the setters */
  private readonly host: /*StyleComponent|StyleCircleComponent|StyleTextComponent*/ any;

  @Input() color: Color | undefined;
  @Input() lineCap: 'butt' | 'round' | 'square' | undefined;
  @Input() lineDash: Array<number> | undefined;
  @Input() lineJoin: 'round' | 'bevel' | 'miter' | undefined;
  @Input() miterLimit: number | undefined;
  @Input() width: number | undefined;

  constructor(
    @Optional() styleHost: StyleComponent,
    @Optional() styleCircleHost: StyleCircleComponent,
    @Optional() styleTextHost: StyleTextComponent
  ) {
    if (!styleHost) {
      throw new Error('map-style-stroke must be a descendant of aol-style');
    }
    // tslint:disable-next-line: prefer-conditional-expression
    if (!!styleTextHost) {
      this.host = styleTextHost;
    } else if (!!styleCircleHost) {
      this.host = styleCircleHost;
    } else {
      this.host = styleHost;
    }
  }

  ngOnInit(): void {
    this.instance = new Stroke(this);
    switch (this.host.componentType) {
      case 'style':
        this.host.instance.setStroke(this.instance);
        break;
      case 'style-text':
        this.host.instance.setStroke(this.instance);
        break;
      case 'style-circle':
        this.host.stroke = this.instance;
        // console.log('setting ol.style.circle instance\'s stroke:', this.host);
        break;
      default:
        throw new Error(`unknown host type: ${this.host}`);
      // break;
    }
  }

  ngOnChanges(changes: SimpleChanges): void {
    if (!this.instance) {
      return;
    }
    if (changes.color) {
      this.instance.setColor(changes.color.currentValue);
    }
    if (changes.lineCap) {
      this.instance.setLineCap(changes.lineCap.currentValue);
    }
    if (changes.lineDash) {
      this.instance.setLineDash(changes.lineDash.currentValue);
    }
    if (changes.lineJoin) {
      this.instance.setLineJoin(changes.lineJoin.currentValue);
    }
    if (changes.miterLimit) {
      this.instance.setMiterLimit(changes.miterLimit.currentValue);
    }
    if (changes.width) {
      this.instance.setWidth(changes.width.currentValue);
    }
    this.host.update();
  }
}
